import{_ as e,c as t,o,a1 as i}from"./chunks/framework.DILC4Csi.js";const c=JSON.parse('{"title":"Платформы: Функции запроса | opencode-mystatus","description":"Узнайте о функциях запроса квот для 4 ИИ-платформ. Поддержка OpenAI, Zhipu AI, GitHub Copilot и Google Cloud.","frontmatter":{"title":"Платформы: Функции запроса | opencode-mystatus","sidebarTitle":"Платформы","subtitle":"Платформы: Функции запроса","description":"Узнайте о функциях запроса квот для 4 ИИ-платформ. Поддержка OpenAI, Zhipu AI, GitHub Copilot и Google Cloud.","order":2},"headers":[],"relativePath":"ru/vbgate/opencode-mystatus/platforms/index.md","filePath":"ru/vbgate/opencode-mystatus/platforms/index.md"}'),l={name:"ru/vbgate/opencode-mystatus/platforms/index.md"};function r(d,a,u,n,h,s){return o(),t("div",null,[...a[0]||(a[0]=[i('<h1 id="функции-платформ" tabindex="-1">Функции платформ <a class="header-anchor" href="#функции-платформ" aria-label="Permalink to &quot;Функции платформ&quot;">​</a></h1><p>Этот раздел подробно описывает функции запроса квот ИИ-платформ, поддерживаемых opencode-mystatus.</p><h2 id="поддерживаемые-платформы" tabindex="-1">Поддерживаемые платформы <a class="header-anchor" href="#поддерживаемые-платформы" aria-label="Permalink to &quot;Поддерживаемые платформы&quot;">​</a></h2><p>opencode-mystatus поддерживает следующие 4 основные ИИ-платформы:</p><table tabindex="0"><thead><tr><th>Платформа</th><th>Тип лимита</th><th>Особенности</th></tr></thead><tbody><tr><td>OpenAI</td><td>3 часа / 24 часа скользящее окно</td><td>Поддерживает подписки Plus/Team/Pro</td></tr><tr><td>Zhipu AI</td><td>5 часов Token / ежемесячная квота MCP</td><td>Поддерживает Coding Plan</td></tr><tr><td>GitHub Copilot</td><td>Ежемесячная квота</td><td>Отображает использование Premium Requests</td></tr><tr><td>Google Cloud</td><td>По моделям независимо</td><td>Поддерживает несколько аккаунтов, 4 модели</td></tr></tbody></table><h2 id="подробности-платформ" tabindex="-1">Подробности платформ <a class="header-anchor" href="#подробности-платформ" aria-label="Permalink to &quot;Подробности платформ&quot;">​</a></h2><h3 id="квота-openai" tabindex="-1"><a href="./openai-usage/">Квота OpenAI</a> <a class="header-anchor" href="#квота-openai" aria-label="Permalink to &quot;[Квота OpenAI](./openai-usage/)&quot;">​</a></h3><p>Узнайте глубже о механизме запроса квот OpenAI:</p><ul><li>Различие между скользящими окнами 3 часов и 24 часов</li><li>Механизм совместного использования квот командных аккаунтов</li><li>Анализ JWT Token для получения информации об аккаунте</li></ul><h3 id="квота-zhipu-ai" tabindex="-1"><a href="./zhipu-usage/">Квота Zhipu AI</a> <a class="header-anchor" href="#квота-zhipu-ai" aria-label="Permalink to &quot;[Квота Zhipu AI](./zhipu-usage/)&quot;">​</a></h3><p>Узнайте о запросе квот Zhipu AI и Z.ai:</p><ul><li>Способ расчёта лимита Token за 5 часов</li><li>Назначение ежемесячной квоты MCP</li><li>Маскировка отображения API Key</li></ul><h3 id="квота-github-copilot" tabindex="-1"><a href="./copilot-usage/">Квота GitHub Copilot</a> <a class="header-anchor" href="#квота-github-copilot" aria-label="Permalink to &quot;[Квота GitHub Copilot](./copilot-usage/)&quot;">​</a></h3><p>Освойте управление квотами GitHub Copilot:</p><ul><li>Значение Premium Requests</li><li>Различие в квотах разных типов подписок</li><li>Расчёт времени ежемесячного сброса</li></ul><h3 id="квота-google-cloud" tabindex="-1"><a href="./google-usage/">Квота Google Cloud</a> <a class="header-anchor" href="#квота-google-cloud" aria-label="Permalink to &quot;[Квота Google Cloud](./google-usage/)&quot;">​</a></h3><p>Узнайте запрос квот нескольких аккаунтов Google Cloud:</p><ul><li>Различие 4 моделей (G3 Pro, G3 Image, G3 Flash, Claude)</li><li>Управление и переключение нескольких аккаунтов</li><li>Механизм чтения файлов аутентификации</li></ul><h2 id="руководство-по-выбору" tabindex="-1">Руководство по выбору <a class="header-anchor" href="#руководство-по-выбору" aria-label="Permalink to &quot;Руководство по выбору&quot;">​</a></h2><p>Выберите соответствующее руководство в зависимости от используемых платформ:</p><ul><li><strong>Только OpenAI</strong>: сразу смотрите <a href="./openai-usage/">Квота OpenAI</a></li><li><strong>Только Zhipu AI</strong>: сразу смотрите <a href="./zhipu-usage/">Квота Zhipu AI</a></li><li><strong>Многоплатформенный пользователь</strong>: рекомендуется последовательно прочитать все руководства по платформам</li><li><strong>Пользователи Google Cloud</strong>: нужно сначала установить плагин <a href="https://github.com/NoeFabris/opencode-antigravity-auth" target="_blank" rel="noreferrer">opencode-antigravity-auth</a></li></ul><h2 id="следующие-шаги" tabindex="-1">Следующие шаги <a class="header-anchor" href="#следующие-шаги" aria-label="Permalink to &quot;Следующие шаги&quot;">​</a></h2><p>После завершения этого раздела вы можете продолжить изучение <a href="./../advanced/">Дополнительные функции</a>, чтобы узнать больше вариантов конфигурации.</p>',23)])])}const g=e(l,[["render",r]]);export{c as __pageData,g as default};
